import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import { useReport } from "@/lib/report-context"
import { ArrowLeft, ArrowRight, Edit2, Loader } from "lucide-react"

interface ExtractedField {
  label: string
  value: string
  confidence?: number
  editable?: boolean
}

export function AIExtractionPage() {
  const router = useRouter()
  const { reportData, updateReportData } = useReport()
  const [isProcessing, setIsProcessing] = useState(true)
  const [editingField, setEditingField] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)

  const [fields, setFields] = useState<Record<string, string>>({
    category: "Checking...",
    address: "Checking...",
    city: "Checking...",
    pincode: "Checking...",
    description: reportData.description || "Checking...",
    urgency: "Checking...",
  })

  // Start Gemini AI extraction
  useEffect(() => {
    async function extractInfoWithGemini() {
      try {
        // Base prompt to extract info
        const promptText = `
          Extract complaint details from the following user description.
          Return a JSON object exactly with these keys: 
          "category" (like Pothole, Garbage, Streetlight, Water, etc), 
          "address" (street, landmark), 
          "city", 
          "pincode" (if found), 
          "description" (cleaned up issue details), 
          "urgency" (Low, Medium, or High based on issue type).

          User description: "${reportData.description || "Found a broken streetlight in central park, new delhi 110001 near main gate"}"
        `;

        // Using next.js API route to make the call to protect API key
        const response = await fetch("/api/extract", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({ prompt: promptText }),
        });

        if (!response.ok) throw new Error("Failed to process data");

        const data = await response.json();

        // Map data to fields state
        setFields({
          category: data.category || "General Issue",
          address: data.address || "Unknown Address",
          city: data.city || "Unknown City",
          pincode: data.pincode || "",
          description: data.description || "No description provided",
          urgency: data.urgency || "Medium",
        });
      } catch (err) {
        console.error("AI Error:", err);
        setError("AI could not extract features properly. You might need to fill them manually.");
        // fallback to defaults if AI fails
        setFields({
          category: "General Issue",
          address: "Unknown Address",
          city: "Unknown City",
          pincode: "",
          description: reportData.description || "",
          urgency: "Medium",
        })
      } finally {
        setIsProcessing(false)
      }
    }

    extractInfoWithGemini();
  }, [reportData.description]);

