import { GoogleGenerativeAI } from "@google/generative-ai";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  try {
    const { prompt } = await req.json();

    if (!process.env.GEMINI_API_KEY) {
      return NextResponse.json({ error: "Missing API Key" }, { status: 500 });
    }

    const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
    const model = genAI.getGenerativeModel({ model: "gemini-1.5-pro-latest" });

    // Enforcing exact JSON format to read on frontend
    const finalPrompt = `
      You are an AI assistant that extracts details about civic issues/complaints.
      Read the following text and reply ONLY with a valid JSON object matching this structure:
      {
        "category": "string (e.g. Pothole, Streetlight, Garbage, Water Issue)",
        "address": "string",
        "city": "string",
        "pincode": "string",
        "description": "string (cleaned up)",
        "urgency": "Low, Medium, or High"
      }

      Text to extract: "${prompt}"
    `;

    const result = await model.generateContent(finalPrompt);
    const response = await result.response;
    const text = response.text();

    // Cleaning the response string in case Gemini added markdown blocks
    const cleanedJson = text.replace(/```json\n|```\n|```/g, "").trim();
    const data = JSON.parse(cleanedJson);

    return NextResponse.json(data);
  } catch (error) {
    console.error("Gemini API Error:", error);
    return NextResponse.json(
      { error: "Failed to generate extraction" },
      { status: 500 }
    );
  }
}

