import { NextRequest, NextResponse } from "next/server";
import { flashModel } from "@/lib/gemini";

const SYSTEM_PROMPT = `You are a civic complaint intake agent for FixMyCity India.
Language: Respond ONLY in Hindi/Hinglish. Keep sentences short and conversational.
Goal: Extract these fields via conversation:
  description, address, city, pincode, urgency (High/Medium/Low)

Return ONLY valid JSON (no markdown):
{
  "agent_reply": "<Hindi/Hinglish reply asking for missing details or confirming>",
  "extracted": {
    "description": "extracted or 'Extracting...'",
    "address": "extracted or 'Extracting...'",
    "city": "extracted or 'Extracting...'",
    "pincode": "extracted or '...'",
    "urgency": "High/Medium/Low"
  },
  "complete": false
}

When all fields are provided, set complete: true and end conversation gracefully.`;

export async function POST(req: NextRequest) {
  try {
    const { history, userMessage } = await req.json();

    // Build conversation as text for Gemini
    const historyText = (history || [])
      .map((h: any) => `${h.role === "user" ? "User" : "Assistant"}: ${h.content}`)
      .join("\n");

    const prompt = `${SYSTEM_PROMPT}

${historyText ? "Conversation so far:\n" + historyText + "\n" : ""}User: ${userMessage}`;

    const result = await flashModel.generateContent(prompt);
    const text = result.response.text().trim();

    // Strip markdown formatting if any
    const startIndex = text.indexOf("{");
    const endIndex = text.lastIndexOf("}");
    if (startIndex === -1 || endIndex === -1) {
      return NextResponse.json({ success: false, error: "Invalid JSON format returned" }, { status: 500 });
    }

    const clean = text.substring(startIndex, endIndex + 1);
    const parsed = JSON.parse(clean);

    return NextResponse.json({ success: true, data: parsed });
  } catch (err) {
    console.error("voice-agent error:", err);
    return NextResponse.json({ success: false, error: "Voice agent failed" }, { status: 500 });
  }
}

